output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?game ?gameLabel ?mainCharacter ?mainCharacterLabel WHERE {
  ?game wdt:P123 wd:Q2617855 .
  ?game wdt:P577 "2016-10-06" ^^ xsd:date .
  ?game wdt:P1322 wd:Q2654839 .
  ?game wdt:P170 ?mainCharacter .
  OPTIONAL {
    ?game rdfs:label ?gameLabel
    FILTER(LANG(?gameLabel) = "en")
  }
  OPTIONAL {
    ?mainCharacter rdfs:label ?mainCharacterLabel
    FILTER(LANG(?mainCharacterLabel) = "en")
  }
}

